INSERT OR REPLACE INTO course (id, slug, title, description, short_description, image_url, image_alt, price_cents, stripe_price_id, is_free, has_certificate, certificate_quiz_step_id, self_paced, access_type, coming_soon, participants, instructors_json, includes_json, included_in_json, settings_json, seo_json, faqs_json, sort_order, status) VALUES ('masterclass-endo-surgery', 'masterclass-in-endometriosis-and-surgery', 'Masterclass in Endometriosis & Surgery', 'Take control of your endometriosis journey with this comprehensive masterclass led by Dr. Naomi Whittaker, a NaProTechnology trained OBGYN and endometriosis specialist.' || char(10) || '' || char(10) || 'Designed for both women living with endometriosis and healthcare professionals, this course offers:' || char(10) || '' || char(10) || '• Clarity and understanding — Debunk common myths and gain in-depth knowledge about endometriosis and its impact on fertility.' || char(10) || '' || char(10) || '• Surgical insights — Explore various surgical approaches, including NaProTechnology''s meticulous techniques and focus on adhesion prevention.' || char(10) || '' || char(10) || '• Informed decision-making — Learn how to choose the right endometriosis surgeon for you and navigate the surgical process with confidence.' || char(10) || '' || char(10) || '• Long-term management — Discover effective strategies for managing endometriosis symptoms through lifestyle changes, supplements, and medications.' || char(10) || '' || char(10) || 'Whether you''re considering surgery, waiting for an appointment, or seeking to better guide your patients, this masterclass empowers you with the knowledge and tools you need to find lasting relief and achieve your fertility goals.', 'Comprehensive guide for patients preparing for endometriosis surgery. Covers the entire surgical journey, including how to choose a surgeon, and automatically includes the Long-Term Management course as a bonus.', '/api/assets/courses/masterclass-endo-surgery/cover.jpeg', 'a woman sits in front of a microphone and a laptop', 19900, 'price_1T4SQrAYnsgNHm0HnDTyevzw', 0, 1, 'mc-feedback-3', 1, 'public', 0, 79, '[{"name":"Naomi Whittaker, MD","role":"Lead Instructor"},{"name":"RRM Academy","role":"Organization"}]', '["long-term-endometriosis-management"]', NULL, '{"stepOrder":"fixed","futureStepContent":"hidden","videoWatchRequirement":0.9,"autoplayNextVideo":true}', '{"title":"Masterclass in Endometriosis and Surgery | RRM Academy","description":"This essential course equips both women with endometriosis and healthcare professionals with the knowledge and tools for effective long-term symptom management.","keywords":["Endometriosis"]}', '[{"question":"Who is this course for?","answer":"This course is designed for patients preparing for endometriosis surgery or considering it. It''s also valuable for women recently diagnosed with endometriosis who want to understand all treatment options, and for partners or family members who want to support someone through the surgical journey."},{"question":"Do I need medical training to take this course?","answer":"No. This course is written for patients, not clinicians. Dr. Whittaker explains medical concepts in plain language with visual aids. Healthcare professionals will also find it valuable for understanding the patient perspective."},{"question":"What will I be able to do after this course?","answer":"You''ll know how to evaluate and choose an endometriosis surgeon, understand what to expect before, during, and after surgery, know the right questions to ask your doctor, and have a long-term management plan for living well with endometriosis."},{"question":"Is this course accredited for CME credits?","answer":"This course is not currently CME-accredited. It is designed as patient education. Healthcare professionals seeking CME should check the IIRRM and FACTS About Fertility course catalogs for accredited options."},{"question":"How long do I have access to the course?","answer":"You have one year of access from the date of purchase. This gives you time to revisit materials as you prepare for and recover from surgery."},{"question":"Does the course include the Long-Term Management course?","answer":"Yes. When you purchase the Masterclass in Endometriosis & Surgery, the Long-Term Endometriosis Management course ($19 value) is automatically included as a bonus."},{"question":"Can I get a scholarship?","answer":"As a 501(c)(3) nonprofit, RRM Academy offers a limited number of scholarships for paid courses. Contact us to request a scholarship application."},{"question":"What topics does the curriculum cover?","answer":"The course has 9 sections and 46 lessons covering: introduction to endometriosis, choosing a surgeon, surgical preparation, what happens during surgery, recovery, long-term management (diet, lifestyle, supplements, medications), and when to seek additional care."}]', 0, 'published');
