INSERT OR REPLACE INTO course (id, slug, title, description, short_description, image_url, image_alt, price_cents, stripe_price_id, is_free, has_certificate, certificate_quiz_step_id, self_paced, access_type, coming_soon, participants, instructors_json, includes_json, included_in_json, settings_json, seo_json, faqs_json, sort_order, status) VALUES ('long-term-endo', 'long-term-endometriosis-management', 'Long Term Endometriosis Management', 'This essential course equips both women with endometriosis and healthcare professionals with the knowledge and tools for effective long-term symptom management.' || char(10) || '' || char(10) || 'For Patients:' || char(10) || '• Empowerment through Knowledge — Gain a deep understanding of how lifestyle, diet, supplements, and medications can influence your endometriosis symptoms.' || char(10) || '• Practical Strategies — Discover actionable steps to implement in your daily life for improved well-being and reduced pain.' || char(10) || '• Holistic Approach — Explore a range of evidence-based and complementary therapies to manage endometriosis holistically.' || char(10) || '' || char(10) || 'For Healthcare Professionals:' || char(10) || '• Expand Your Expertise — Enhance your understanding of long-term endometriosis management strategies beyond surgical interventions.' || char(10) || '• Guide Your Patients — Gain valuable insights to confidently advise and support your patients in managing their endometriosis symptoms.' || char(10) || '• Improve Patient Outcomes — Discover effective tools and resources to help your patients achieve lasting relief and improve their quality of life.', 'Non-surgical wellness strategies for endometriosis: diet, lifestyle, supplements, and medications. Can be purchased separately or included with the Masterclass.', '/api/assets/courses/long-term-endo/cover.jpg', '', 1900, 'price_1T4SR1AYnsgNHm0H1HvxVc03', 0, 0, NULL, 1, 'public', 0, 40, '[{"name":"Naomi Whittaker, MD","role":"Lead Instructor"},{"name":"RRM Academy","role":"Organization"}]', NULL, '["masterclass-in-endometriosis-and-surgery"]', '{"stepOrder":"fixed","futureStepContent":"hidden","videoWatchRequirement":0.9,"autoplayNextVideo":false}', '{"title":"Long Term Endometriosis Management | RRM Academy","description":"Evidence-based strategies for long-term endometriosis symptom management through diet, lifestyle, supplements, and medications.","keywords":["Endometriosis","Long-term management"]}', '[{"question":"Who is this course for?","answer":"Women living with endometriosis who want non-surgical strategies for managing symptoms. Ideal for post-surgical patients or those not yet ready for surgery."},{"question":"What topics are covered?","answer":"Diet and nutrition for endometriosis, lifestyle modifications, evidence-based supplements, medications that support long-term management, and when to consider further intervention."},{"question":"How is this different from the Masterclass?","answer":"The Masterclass covers the full surgical journey (46 lessons, 2h 53m) and includes this course as a bonus. This standalone course (7 videos, 15 minutes) focuses specifically on non-surgical management."},{"question":"Is this course free?","answer":"No, it''s $19. RRM Academy offers several free courses if you''d like to start there. Scholarships are available for paid courses."},{"question":"How long do I have access?","answer":"One year from purchase date, or lifetime if you purchased the Masterclass (which includes this course)."}]', 1, 'published');
