INSERT OR REPLACE INTO course (id, slug, title, description, short_description, image_url, image_alt, price_cents, stripe_price_id, is_free, has_certificate, certificate_quiz_step_id, self_paced, access_type, coming_soon, participants, instructors_json, includes_json, included_in_json, settings_json, seo_json, faqs_json, sort_order, status) VALUES ('postpartum', 'postpartum-depression-anxiety', 'Postpartum Depression & Anxiety: A Restorative Approach to Recovery', 'This course discusses postpartum depression and anxiety, exploring its causes, symptoms, and a restorative approach to healing.' || char(10) || '' || char(10) || 'Dr. Naomi Whittaker, a fertility surgeon specializing in women''s health, delves into the limitations of conventional treatments and offers insights into the effectiveness of bioidentical progesterone.' || char(10) || '' || char(10) || 'Key topics covered:' || char(10) || '• Understanding the different types of postpartum mood disorders' || char(10) || '• Exploring the physiological and hormonal factors contributing to postpartum depression' || char(10) || '• Discussing the limitations of traditional treatment approaches like SSRIs' || char(10) || '• Highlighting the benefits of bioidentical progesterone as a natural and effective solution' || char(10) || '• Providing actionable steps for prevention and seeking support', 'Explore postpartum depression and anxiety, its causes and symptoms, and a restorative approach to healing with bioidentical progesterone.', '/api/assets/courses/postpartum/cover.png', 'Postpartum', 0, NULL, 1, 0, NULL, 1, 'public', 0, 42, '[{"name":"Naomi Whittaker, MD","role":"Lead Instructor"},{"name":"RRM Academy","role":"Organization"}]', NULL, NULL, '{"stepOrder":"fixed","futureStepContent":"hidden","videoWatchRequirement":0.9,"autoplayNextVideo":false}', '{"title":"Postpartum Depression & Anxiety: A Restorative Approach | RRM Academy","description":"Learn about postpartum depression and anxiety, its causes, and a restorative approach to recovery using bioidentical progesterone.","keywords":["Postpartum depression","Postpartum anxiety","Bioidentical progesterone"]}', '[{"question":"Who is this course for?","answer":"Anyone affected by postpartum depression or anxiety, including new mothers, their partners, and family members. It is also useful for healthcare providers who want to understand the restorative approach to postpartum mood disorders."},{"question":"What is the restorative approach to postpartum depression?","answer":"Rather than relying solely on SSRIs, this course explores the role of bioidentical progesterone in treating postpartum depression and anxiety. Dr. Whittaker explains the hormonal causes and how restoring progesterone levels can support recovery."},{"question":"How long is the course?","answer":"Six short video lessons totaling about 30 minutes. You can complete it in one sitting or spread it across several days."},{"question":"Is this a replacement for my doctor or therapist?","answer":"No. This course is educational, not clinical. It gives you the knowledge to have more informed conversations with your healthcare provider about treatment options, including ones they may not have discussed with you."},{"question":"Does this course cover postpartum anxiety, not just depression?","answer":"Yes. Dr. Whittaker covers the full spectrum of postpartum mood disorders, including anxiety. The course explains how hormonal changes after birth contribute to both depression and anxiety, and how the restorative approach addresses them."},{"question":"What does bioidentical progesterone have to do with postpartum depression?","answer":"Progesterone levels drop dramatically after delivery. This course explains the research connecting that hormonal crash to postpartum mood disorders and how bioidentical progesterone replacement can help restore balance, offering a different path than SSRIs alone."}]', 2, 'published');
