INSERT OR REPLACE INTO course (id, slug, title, description, short_description, image_url, image_alt, price_cents, stripe_price_id, is_free, has_certificate, certificate_quiz_step_id, self_paced, access_type, coming_soon, participants, instructors_json, includes_json, included_in_json, settings_json, seo_json, faqs_json, sort_order, status) VALUES ('rrm-vs-ivf', 'rrm-vs-ivf', 'Restorative Reproductive Medicine (RRM) vs Standard ART: A New Approach to Infertility', 'This course dives deep into the world of infertility treatment, comparing the standard Assisted Reproductive Technology (ART) like IVF and IUI with a lesser-known approach called Restorative Reproductive Medicine (RRM).' || char(10) || '' || char(10) || 'Dr. Naomi Whittaker, an OBGYN fertility surgeon specializing in RRM, discusses the limitations of conventional infertility treatment and explores the potential of RRM as a more holistic and effective solution.' || char(10) || '' || char(10) || 'Key topics covered:' || char(10) || '• The shortcomings of standard OBGYN training in addressing infertility' || char(10) || '• The facts behind IVF and IUI success rates and their associated risks' || char(10) || '• The ethical, financial, and medical concerns surrounding ART' || char(10) || '• The principles of RRM and its focus on identifying and treating the root causes of infertility' || char(10) || '• Real patient stories showcasing the effectiveness of RRM', 'Compare standard ART (IVF/IUI) with Restorative Reproductive Medicine, exploring root-cause approaches to infertility with real patient stories.', '/api/assets/courses/rrm-vs-ivf/cover.png', 'Naomi Whittaker, MD', 0, NULL, 1, 0, NULL, 1, 'public', 0, 99, '[{"name":"Naomi Whittaker, MD","role":"Lead Instructor"},{"name":"RRM Academy","role":"Organization"}]', NULL, NULL, '{"stepOrder":"fixed","futureStepContent":"hidden","videoWatchRequirement":0.9,"autoplayNextVideo":false}', '{"title":"RRM vs IVF: A New Approach to Infertility | RRM Academy","description":"Compare standard ART like IVF and IUI with Restorative Reproductive Medicine (RRM), a root-cause approach to treating infertility.","keywords":["RRM","IVF","Infertility","Restorative Reproductive Medicine"]}', '[{"question":"Who is this course for?","answer":"Anyone considering fertility treatment who wants to understand all options. This includes patients weighing IVF against restorative approaches, healthcare providers who want to counsel patients about alternatives, and couples at the beginning of their fertility journey."},{"question":"What data sources does this course use?","answer":"The course draws on peer-reviewed research published in journals including Fertility and Sterility, BMC Pregnancy and Childbirth, and the Journal of Restorative Reproductive Medicine. All claims are cited."},{"question":"Will this help me decide between RRM and IVF?","answer":"This course gives you the information to make that decision with your doctor. It covers: how each approach works, published outcomes by condition, cost comparison, what to expect from each treatment path, and questions to ask your provider."},{"question":"Is this course really free?","answer":"Yes, 100% free. RRM Academy is a 501(c)(3) nonprofit. Free courses are part of our mission to make restorative reproductive medicine education accessible to everyone."},{"question":"Do I need to create an account?","answer":"Yes, a free account is required to track your progress and provide access to course materials including downloadable resources and transcripts."},{"question":"How long do I have access?","answer":"Lifetime access. You can revisit the materials anytime."},{"question":"What format are the lessons?","answer":"Self-paced video lectures with downloadable resources and transcripts. You can learn on your own schedule."}]', 3, 'published');
