INSERT OR REPLACE INTO course (id, slug, title, description, short_description, image_url, image_alt, price_cents, stripe_price_id, is_free, has_certificate, certificate_quiz_step_id, self_paced, access_type, coming_soon, participants, instructors_json, includes_json, included_in_json, settings_json, seo_json, faqs_json, sort_order, status) VALUES ('hormones-through-the-lifespan', 'hormones-through-the-lifespan', 'Hormones Through the Lifespan: Cycles, Conditions, and Menopause', 'Dr. Ana Garcia, OB/GYN and NaProTechnology-trained physician, walks through the full arc of female hormonal health: how cycles work, what disrupts them, conditions like PCOS and endometriosis, and how to support the body through perimenopause and menopause with a restorative approach.', 'A comprehensive overview of hormonal health across a woman''s life — menstrual cycles, common conditions, and the transition to menopause — presented by Dr. Ana Garcia, OB/GYN.', '', '', 0, NULL, 0, 0, NULL, 1, 'public', 1, 0, '[{"name":"Dr. Ana Garcia","role":"OB/GYN, NaProTechnology"}]', NULL, NULL, '{"stepOrder":"fixed","futureStepContent":"hidden","videoWatchRequirement":0.9,"autoplayNextVideo":false}', '{"title":"Hormones Through the Lifespan | RRM Academy","description":"Learn how hormones change across a woman''s life — cycles, conditions, and menopause — with Dr. Ana Garcia, OB/GYN.","keywords":[]}', NULL, 4, 'published');
INSERT OR REPLACE INTO course (id, slug, title, description, short_description, image_url, image_alt, price_cents, stripe_price_id, is_free, has_certificate, certificate_quiz_step_id, self_paced, access_type, coming_soon, participants, instructors_json, includes_json, included_in_json, settings_json, seo_json, faqs_json, sort_order, status) VALUES ('pelvic-floor-rehabilitation', 'pelvic-floor-rehabilitation', 'Pelvic Floor Rehabilitation', 'Dr. Amanda Simmons, Doctor of Physical Therapy and pelvic floor specialist at Ascend Pelvic Health, covers the anatomy and function of the pelvic floor, common dysfunctions (pain, prolapse, incontinence), and evidence-based rehabilitation approaches for patients navigating reproductive and pelvic health conditions.', 'Understanding and rehabilitating the pelvic floor — pain, dysfunction, and recovery — with Dr. Amanda Simmons, Physical Therapist at Ascend Pelvic Health.', '', '', 0, NULL, 0, 0, NULL, 1, 'public', 1, 0, '[{"name":"Dr. Amanda Simmons","role":"PT, DPT — Ascend Pelvic Health"}]', NULL, NULL, '{"stepOrder":"fixed","futureStepContent":"hidden","videoWatchRequirement":0.9,"autoplayNextVideo":false}', '{"title":"Pelvic Floor Rehabilitation | RRM Academy","description":"Learn about pelvic floor dysfunction and evidence-based rehabilitation from Dr. Amanda Simmons, pelvic floor physical therapist.","keywords":[]}', NULL, 5, 'published');
INSERT OR REPLACE INTO course (id, slug, title, description, short_description, image_url, image_alt, price_cents, stripe_price_id, is_free, has_certificate, certificate_quiz_step_id, self_paced, access_type, coming_soon, participants, instructors_json, includes_json, included_in_json, settings_json, seo_json, faqs_json, sort_order, status) VALUES ('infertility-existential-trauma', 'infertility-existential-trauma', 'Infertility as Existential Trauma', 'Dr. Clay Brigance, Licensed Professional Counselor and researcher, examines infertility as a form of existential trauma and PTSD. This session covers the psychological impact of fertility struggles, grief responses, and therapeutic approaches that help patients process and heal — essential knowledge for both patients and the providers who support them.', 'The psychological and existential toll of infertility — trauma, grief, and PTSD — explored through a clinical lens by Dr. Clay Brigance, LPC.', '', '', 0, NULL, 0, 0, NULL, 1, 'public', 1, 0, '[{"name":"Dr. Clay Brigance","role":"LPC, Infertility Researcher — Shiloh Counseling"}]', NULL, NULL, '{"stepOrder":"fixed","futureStepContent":"hidden","videoWatchRequirement":0.9,"autoplayNextVideo":false}', '{"title":"Infertility as Existential Trauma | RRM Academy","description":"Understand the psychological and existential dimensions of infertility with Dr. Clay Brigance, LPC and researcher.","keywords":[]}', NULL, 6, 'published');
INSERT OR REPLACE INTO course (id, slug, title, description, short_description, image_url, image_alt, price_cents, stripe_price_id, is_free, has_certificate, certificate_quiz_step_id, self_paced, access_type, coming_soon, participants, instructors_json, includes_json, included_in_json, settings_json, seo_json, faqs_json, sort_order, status) VALUES ('fertility-based-family-planning', 'fertility-based-family-planning', 'Fertility-Based Methods of Family Planning: New Horizons', 'Dr. William Nolan presents the current landscape of fertility-based methods of family planning (FBMFPs), including the latest research, emerging methods, and how these approaches align with NaProTechnology and restorative reproductive medicine principles. Designed for both providers and patients seeking alternatives to hormonal contraception.', 'An evidence-based overview of fertility awareness and NaProTechnology-aligned family planning methods, presented by Dr. William Nolan.', '', '', 0, NULL, 0, 0, NULL, 1, 'public', 1, 0, '[{"name":"Dr. William Nolan","role":"FABM Specialist, Tubal Surgery"}]', NULL, NULL, '{"stepOrder":"fixed","futureStepContent":"hidden","videoWatchRequirement":0.9,"autoplayNextVideo":false}', '{"title":"Fertility-Based Methods of Family Planning | RRM Academy","description":"Explore evidence-based fertility awareness and family planning methods with Dr. William Nolan.","keywords":[]}', NULL, 7, 'published');
INSERT OR REPLACE INTO course (id, slug, title, description, short_description, image_url, image_alt, price_cents, stripe_price_id, is_free, has_certificate, certificate_quiz_step_id, self_paced, access_type, coming_soon, participants, instructors_json, includes_json, included_in_json, settings_json, seo_json, faqs_json, sort_order, status) VALUES ('aip-diet-inflammation', 'aip-diet-inflammation', 'Why the AIP Diet Is Not Enough to Reduce Inflammation', 'Rita Johnson, functional medicine practitioner, breaks down the science and limitations of the Autoimmune Protocol (AIP) diet for patients managing chronic inflammation, endometriosis, PCOS, and other reproductive conditions. Learn what diet alone cannot address, and what a comprehensive anti-inflammatory protocol — including gut health, lifestyle, and targeted support — actually requires.', 'Functional medicine practitioner Rita Johnson explains why the Autoimmune Protocol diet alone falls short — and what a complete anti-inflammatory strategy actually looks like.', '', '', 0, NULL, 0, 0, NULL, 1, 'public', 1, 0, '[{"name":"Rita Johnson","role":"Functional Medicine Practitioner"}]', NULL, NULL, '{"stepOrder":"fixed","futureStepContent":"hidden","videoWatchRequirement":0.9,"autoplayNextVideo":false}', '{"title":"Why the AIP Diet Is Not Enough | RRM Academy","description":"Learn why the AIP diet alone isn''t enough to reduce inflammation — and what a complete anti-inflammatory strategy looks like.","keywords":[]}', NULL, 8, 'published');
INSERT OR REPLACE INTO course (id, slug, title, description, short_description, image_url, image_alt, price_cents, stripe_price_id, is_free, has_certificate, certificate_quiz_step_id, self_paced, access_type, coming_soon, participants, instructors_json, includes_json, included_in_json, settings_json, seo_json, faqs_json, sort_order, status) VALUES ('functional-lab-testing-napro', 'functional-lab-testing-napro', 'Functional Lab Testing, NaPro Technology, and Preconception Care', 'Dr. Ana Garcia (OB/GYN), Hannah Ducote (RN, fertility coach), and Elena Climov (FNP-C, IFMCP) discuss how functional lab testing integrates with NaProTechnology and RRM protocols to support preconception care. Topics include hormone panels, thyroid, micronutrient testing, and how to use data to guide targeted preconception support.', 'A panel discussion on functional lab testing, NaProTechnology protocols, and preconception care with Dr. Ana Garcia, Hannah Ducote, and Elena Climov.', '', '', 0, NULL, 0, 0, NULL, 1, 'public', 1, 0, '[{"name":"Dr. Ana Garcia","role":"OB/GYN, NaProTechnology"},{"name":"Hannah Ducote","role":"RN, Fertility Coach"},{"name":"Elena Climov","role":"FNP-C, IFMCP"}]', NULL, NULL, '{"stepOrder":"fixed","futureStepContent":"hidden","videoWatchRequirement":0.9,"autoplayNextVideo":false}', '{"title":"Functional Lab Testing, NaPro Technology & Preconception Care | RRM Academy","description":"Panel discussion on functional lab testing and NaProTechnology-aligned preconception protocols with Dr. Ana Garcia, Hannah Ducote, and Elena Climov.","keywords":[]}', NULL, 9, 'published');
